Sorry, just had some time to look into this. I found a way to do it, but I haven't found a good way to integrate it into the code base. The tricky thing here is the way the config and creds are set up. However, here's some code to do what you want:

```
from googleapiclient import discovery
from gspread_pandas import Spread
s = Spread('<id>', '<spreadsheet>')

drive_service = discovery.build('drive', 'v3', credentials=s.client.auth).files()

def find_all_sheets(folder_name):
    results = {}
    for res in find_folders(folder_name):
        results.update(res)
    return results

def find_sheets(folder_id):
    page_token = None
    while True:
        response = drive_service.list(q="mimeType='application/vnd.google-apps.spreadsheet' and '{0}' in parents".format(folder_id),
                                      spaces='drive',
                                      fields='nextPageToken, files(id, name)',
                                      pageToken=page_token).execute()
        for sheet in response.get('files', []):
            # Process change
            yield Spread('difernan', sheet.get('id'))
            page_token = response.get('nextPageToken')

        if page_token is None:
            break


def find_folders(folder_name):
    page_token = None
    while True:
        response = drive_service.list(q="mimeType='application/vnd.google-apps.folder' and name contains '{0}'".format(folder_name),
                                      spaces='drive',
                                      fields='nextPageToken, files(id, name)',
                                      pageToken=page_token).execute()

        for folder in response.get('files', []):
            f = {}
            f[folder.get('name')] = [sheet for sheet in find_sheets(folder.get('id'))]
            yield f
            page_token = response.get('nextPageToken', None)

        if page_token is None:
            break
```

This will search for any directories containing some string, and create a dictionary with the keys being the matching folder names, and the values being a list of all spreadsheets in that directory. I'll continue to think on how to best integrate this.

`ItemAttachment` has an `item` attribute which points to the actual item that is attached. So to access attachments of attachments, you would do this:

```python
